    let pendingDataCb: Function | null = null;
    let pendingAbortCb: Function | null = null;
    let pendingMapCb: Function | null = null;

    const source = (abort: any, cb: Function) => {
      if (abort) {
        pendingAbortCb = cb;
      } else {
        pendingDataCb = cb; // hold data response
      }
