    };

    const through = asyncMap(mapper);
    const stream = through(source);

    // Step 1: Start a data read - source holds
    // busy = false (map hasn't started)
    stream(null, () => {});

    // Step 2: Abort while not busy (data read is pending but map hasn't started)
    const abortError = new Error("abort");
    let abortCallbackCalled = false;
    stream(abortError, (err: any) => {
      abortCallbackCalled = true;
      expect(err).toBe(abortError);
      done();
    });

    // Step 3: Source responds to data read AFTER abort was called
    // This makes busy = true (map starts)
    if (pendingDataCb) pendingDataCb(null, 42);

    // Step 4: Source responds to abort read
    // Original: fn1 runs, cb(abort) called directly
    // Mutated: fn2 runs, busy=true so abortCb=cb, cb NOT called
    if (pendingAbortCb) pendingAbortCb(abortError);

    // Step 5: Map completes
    // Original: abort already called, done
    // Mutated: abortCb set but aborted=undefined, so cb(null,data) called, abortCb never called
    if (pendingMapCb) pendingMapCb(null, 100);

    // Give time for any async operations
    setTimeout(() => {
      if (!abortCallbackCalled) {
        done.fail("Abort callback was never called");
      }
    }, 100);
  });
